**Supporting Files:**
- `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775497509819-cixdbs/src/models.js` (8,905 lines)
  - AutoModel classes and model imports
- `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775497509819-cixdbs/src/models/auto/processing_auto.js`
  - AutoProcessor factory class

### 2. **Base Pipeline Class Structure**

**Class Definition (lines 164-185):**
```javascript
export class Pipeline extends Callable {
    constructor({ task, model, tokenizer = null, processor = null }) {
        super();
        this.task = task;
        this.model = model;
        this.tokenizer = tokenizer;
        this.processor = processor;
    }

    async dispose() {
        await this.model.dispose();
    }
}
```

**Key Properties:**
- `task`: String identifier for the pipeline (e.g., 'image-to-text', 'zero-shot-image-classification')
- `model`: The pretrained model instance (PreTrainedModel)
- `tokenizer`: Optional tokenizer (AutoTokenizer) for text-based pipelines
- `processor`: Optional processor (AutoProcessor) for multimodal/image/audio pipelines

### 3. **Multimodal Pipeline Examples**

#### Example 1: **ImageToTextPipeline** (lines 1975-2005)
Text+Image (image captioning)
```javascript
export class ImageToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageToTextPipelineType} */ (Pipeline)) {
    constructor(options) {
        super(options);
    }

    async _call(images, generate_kwargs = {}) {
        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);

        const { pixel_values } = await this.processor(preparedImages);

        const toReturn = [];
        for (const batch of pixel_values) {
            batch.dims = [1, ...batch.dims]
            const output = await this.model.generate({ inputs: batch, ...generate_kwargs });
            const decoded = this.tokenizer.batch_decode(output, {
                skip_special_tokens: true,
            }).map(x => ({ generated_text: x.trim() }))
            toReturn.push(decoded);
        }

        return isBatched ? toReturn : toReturn[0];
    }
}
```

**Pattern:**
- Uses `TextImagePipelineConstructorArgs` (has both tokenizer and processor)
- `_call` method accepts images
- Processor handles image input → `pixel_values`
- Model generates output
- Tokenizer decodes the output

---

#### Example 2: **ZeroShotImageClassificationPipeline** (lines 2389-2444)
Text+Image (CLIP-like models)
```javascript
export class ZeroShotImageClassificationPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ZeroShotImageClassificationPipelineType} */ (Pipeline)) {
    constructor(options) {
        super(options);
    }

    async _call(images, candidate_labels, {
        hypothesis_template = "This is a photo of {}"
    } = {}) {
        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);

        // Process text with tokenizer
        const texts = candidate_labels.map(x => hypothesis_template.replace('{}', x));
        const text_inputs = this.tokenizer(texts, {
            padding: this.model.config.model_type === 'siglip' ? 'max_length' : true,
            truncation: true,
        });

        // Process images with processor
        const { pixel_values } = await this.processor(preparedImages);

        // Run model with BOTH text and pixel inputs
        const output = await this.model({ ...text_inputs, pixel_values });

        const function_to_apply =
            this.model.config.model_type === 'siglip'
